// Named groups + replace with a rearranged format
const iso = '2026-07-01';
iso.replace(/(?<y>\d{4})-(?<m>\d{2})-(?<d>\d{2})/, '$<d>/$<m>/$<y>');
// -> '01/07/2026'

// Access captures by name
const m = /(?<area>\d{3})-(?<line>\d{4})/.exec('555-1234');
m.groups.area; // '555'
m.groups.line; // '1234'

// Backreference: find a doubled word
/\b(\w+)\s+\1\b/.test('the the cat'); // true  (\1 re-matches 'the')
/\b(\w+)\s+\1\b/.test('the cat');     // false

// Password rule: at least one lowercase, one uppercase, one digit, min length 8
const strong = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d).{8,}$/;
strong.test('Passw0rd');  // true
strong.test('password');  // false (no uppercase, no digit)

// Lookahead/lookbehind for a thousands separator (insert commas)
'1234567'.replace(/\B(?=(\d{3})+(?!\d))/g, ','); // '1,234,567'

// Negative lookbehind: match 'foo' not preceded by 'bar'
'barfoo foo'.match(/(?<!bar)foo/g); // ['foo'] (the standalone one)

// Without u, . sees surrogate halves; with u it sees code points
'\u{1F600}'.match(/./u).length;          // 1 code point matched

// Unicode property escapes (require the u flag)
/\p{L}+/u.test('caf\u00e9');             // true (letters incl. accented)
/^\p{Lu}/u.test('\u00c9cole');           // true (starts with uppercase letter)

// Sticky flag: match only exactly at lastIndex, used in tokenizers
const t = /\d+/y; t.lastIndex = 3;
t.test('abc123');                        // true, anchored at index 3

// Collapse runs of whitespace to a single space
'  a   b\t c '.replace(/\s+/g, ' ').trim();  // 'a b c'

// A pragmatic (not RFC-complete) email sanity check
const emailish = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
emailish.test('dev@example.com');  // true
emailish.test('not-an-email');     // false

// Extract all http/https URLs (deliberately simple)
const text = 'see https://a.dev and http://b.io/x';
text.match(/https?:\/\/[^\s]+/g);  // ['https://a.dev', 'http://b.io/x']

// ISO-8601 date with validation left to Date
'2026-07-01'.match(/^\d{4}-\d{2}-\d{2}$/); // structural check only

// VULNERABLE: nested quantifiers over overlapping input
const bad = /^(a+)+$/;
// bad.test('aaaaaaaaaaaaaaaaaaaaaaaaaaX') can take seconds -> minutes.
// The 'X' guarantees final failure, forcing full backtracking search.

// Other classic red flags:
const bad2 = /^(\w+\s?)*$/;      // overlapping \w and \s? explode
const bad3 = /(.*a){20}/;        // repeated greedy .* is a red flag

// SAFE rewrite of /^(a+)+$/ - a single, unambiguous quantifier
const good = /^a+$/;
good.test('aaaaaaaaaaaaaaaaaaaaaaaaaaX'); // false, fast (linear)

// Atomic group (engines that support it, e.g. Java/PCRE/.NET):
//   /^(?>a+)+$/  prevents the inner group from giving characters back.
// In JavaScript, emulate an atomic group with lookahead + backreference:
//   /^(?=(a+))\1$/  captures the greedy run once, no re-partitioning.

// Instead of a fragile 'quoted string' matcher that backtracks:
//   BAD:  /"(.*)"/           // .* is greedy and ambiguous inside quotes
//   GOOD: /"([^"\\]*(?:\\.[^"\\]*)*)"/  // unambiguous 'unrolled loop'
const quoted = /"([^"\\]*(?:\\.[^"\\]*)*)"/;
quoted.test('say "hi" now'); // true, matches the quoted span with no blow-up

