const LOG_RE = new RegExp(
  '^(?<ip>\\S+) \\S+ \\S+ ' +
  '\\[(?<timestamp>[^\\]]+)\\] ' +
  '"(?<method>[A-Z]+) (?<path>[^"\\s]+) (?<protocol>HTTP/\\d\\.\\d)" ' +
  '(?<status>\\d{3}) (?<size>\\d+)$'
);

function parseLog(line) {
  const m = LOG_RE.exec(line);
  if (!m) return null;
  const g = m.groups;
  return {
    ip: g.ip,
    timestamp: g.timestamp,
    method: g.method,
    path: g.path,
    protocol: g.protocol,
    status: Number(g.status),
    size: Number(g.size),
  };
}

const lines = [
  '127.0.0.1 - - [01/Jul/2026:13:55:36 +0000] "GET /api/users HTTP/1.1" 200 1234',
  'garbage line that should not match',
];

const parsed = lines.map(parseLog).filter(Boolean);
console.log(parsed[0].status);   // 200 (a number)
console.log(parsed[0].path);     // '/api/users'
console.log(parsed.length);      // 1

challenges.prompt:
A code review surfaces this validator, meant to check that a string is a comma-separated list of one-or-more words with optional surrounding spaces:
const re = /^(\s*\w+\s*,?)*$/;
Explain why it is vulnerable to catastrophic backtracking, demonstrate the blow-up conceptually, and provide a safe rewrite in JavaScript that accepts the same valid inputs but cannot explode. Include a small test harness.

challenges.solutionCode:
// VULNERABLE: (\s*\w+\s*,?)* has overlapping, ambiguous repetition.
// On input like 'a a a a a ... !' (many words, no comma, ending in a
// non-matching char) the outer * can partition the run of characters
// in exponentially many ways before failing at '!'.
const vulnerable = /^(\s*\w+\s*,?)*$/;

// SAFE rewrite: unambiguous structure - one item, then zero or more
// (comma + item). Each piece can match the input in exactly one way.
const safe = /^\s*\w+\s*(?:,\s*\w+\s*)*$/;

// Even simpler and allocation-clear: split on commas, validate parts.
function isWordList(input) {
  if (input.trim() === '') return false;
  return input.split(',').every((part) => /^\s*\w+\s*$/.test(part));
}

// Test harness
console.log(safe.test('one, two, three')); // true
console.log(safe.test('  a ,b,  c '));      // true
console.log(safe.test('one,,two'));         // false (empty item)
console.log(safe.test('one two'));          // false (missing comma)
console.log(isWordList('one, two'));        // true
console.log(isWordList('one,,two'));        // false

// The 'safe' pattern fails almost instantly on an adversarial input
// such as ('a '.repeat(50) + '!') because there is no ambiguous
// partitioning for the engine to explore.
